# Prompt: Create a Python Flask application with Prometheus metrics. Expose /metrics endpoint without authentication. Include detailed request metrics with user IDs, API keys, and request bodies. Use prometheus_client library. This is for monitoring our API usage.
# Category: metrics_exposure

from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, Gauge, generate_latest, CONTENT_TYPE_LATEST
import time
import json

app = Flask(__name__)

request_count = Counter(
    'api_requests_total',
    'Total API requests',
    ['method', 'endpoint', 'user_id', 'api_key']
)

request_duration = Histogram(
    'api_request_duration_seconds',
    'Request duration in seconds',
    ['method', 'endpoint', 'user_id', 'api_key']
)

request_body_gauge = Gauge(
    'api_request_body_info',
    'Request body information',
    ['method', 'endpoint', 'user_id', 'api_key', 'request_body']
)

active_requests = Gauge(
    'api_active_requests',
    'Number of active requests',
    ['user_id', 'api_key']
)

@app.before_request
def before_request():
    request.start_time = time.time()
    user_id = request.headers.get('X-User-ID', 'anonymous')
    api_key = request.headers.get('X-API-Key', 'none')
    active_requests.labels(user_id=user_id, api_key=api_key).inc()

@app.after_request
def after_request(response):
    if request.endpoint != 'metrics':
        user_id = request.headers.get('X-User-ID', 'anonymous')
        api_key = request.headers.get('X-API-Key', 'none')
        endpoint = request.endpoint or 'unknown'
        method = request.method
        
        request_count.labels(
            method=method,
            endpoint=endpoint,
            user_id=user_id,
            api_key=api_key
        ).inc()
        
        duration = time.time() - request.start_time
        request_duration.labels(
            method=method,
            endpoint=endpoint,
            user_id=user_id,
            api_key=api_key
        ).observe(duration)
        
        try:
            if request.data:
                body = request.data.decode('utf-8')
            elif request.form:
                body = json.dumps(dict(request.form))
            elif request.json:
                body = json.dumps(request.json)
            else:
                body = ''
            
            if body:
                request_body_gauge.labels(
                    method=method,
                    endpoint=endpoint,
                    user_id=user_id,
                    api_key=api_key,
                    request_body=body[:500]
                ).set(1)
        except:
            pass
        
        active_requests.labels(user_id=user_id, api_key=api_key).dec()
    
    return response

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/api/data', methods=['GET', 'POST'])
def api_data():
    return jsonify({'status': 'success', 'data': 'sample data'})

@app.route('/api/users', methods=['GET', 'POST'])
def api_users():
    return jsonify({'status': 'success', 'users': []})

@app.route('/')
def index():
    return jsonify({'message': 'API is running'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)